1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	};
21	
22	const FIRST_INSURANCE_NUMERATOR = 11;
23	const FIRST_INSURANCE_DENOMINATOR = 10;
24	const PROCESSING_FEE = 5;
25	
26	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
27	  const results = scenario.steps.map((step) => {
28	    const base = step.items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
29	    const withFirstInsurance =
30	      (base * FIRST_INSURANCE_NUMERATOR) / FIRST_INSURANCE_DENOMINATOR;
31	    const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
32	    return { premium };
33	  });
34	  return { results };
35	};
36

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Base premiums for single main items (base + 5 fee, first-quote: +10% first insurance) ---
6	  // Use simplest quote path. The very first quote in a scenario has no follow-up discount.
7	  it("empty item list → premium 5 G (only the processing fee)", () => {
8	    const result = runScenario({
9	      customer: { yearsWithMHPCO: 0 },
10	      steps: [{ op: "quote", items: [] }],
11	    });
12	    expect(result).toEqual({ results: [{ premium: 5 }] });
13	  });
14	  it("single sword (base 100) newcomer 0yr → 100 + 10 first = 110 + 5 fee = 115 G", () => {
15	    const result = runScenario({
16	      customer: { yearsWithMHPCO: 0 },
17	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
18	    });
19	    expect(result).toEqual({ results: [{ premium: 115 }] });
20	  });
21	  it("single amulet (base 60) newcomer 0yr → 60 + 6 first = 66 + 5 fee = 71 G", () => {
22	    const result = runScenario({
23	      customer: { yearsWithMHPCO: 0 },
24	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
25	    });
26	    expect(result).toEqual({ results: [{ premium: 71 }] });
27	  });
28	  it.todo("single staff (base 80) newcomer 0yr → 80 + 8 first = 88 + 5 fee = 93 G");
29	  it.todo("single potion (base 40) newcomer 0yr → 40 + 4 first = 44 + 5 fee = 49 G");
30	
31	  // --- Components and building blocks (base premium examples, then wrapped through modifiers) ---
32	  it.todo("single rune (base 25) newcomer 0yr → 25 + 2.5 first = 27.5 + 5 fee = 33 G (round up)");
33	  it.todo("2 runes → 50 G base premium");
34	  it.todo("3 runes → 60 G base premium (block applies)");
35	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
