37	
38	  // --- "Alike" components: same type only ---
39	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
40	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
41	
42	  // --- Item-specific modifiers in isolation ---
43	  it.todo("cursed sword adds 50% of its base premium (curse surcharge = 50 G on a 100 G sword)");
44	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies (+30%)");
45	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
46	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
47	
48	  // --- Modifier scope on multi-item policies ---
49	  it.todo("cursed sword (100) + plain amulet (60) → policy base 160; curse adds 50 (of sword) → 210 before policy modifiers and fee");
50	
51	  // --- Policy-wide modifiers ---
52	  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
53	  it.todo("first insurance carries 10% surcharge on the policy base premium");
54	  it.todo("second quote in scenario gets 15% follow-up discount");
55	  it.todo("first insurance applies per item per quote regardless of customer history");
56	
57	  // --- Rounding ---
58	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
59	
60	  // --- Integration examples ---
61	  it.todo("newcomer cursed sword (steel, ench 3), 0yr → 165 G (100 + 50 curse + 10 first + 5 fee)");
62	  it.todo("long-standing 3yr 2nd quote, cursed sword (steel, ench 7) → 160 G (100 + 50 + 30 − 20 loyalty + 10 first − 15 follow-up + 5 fee)");
63	
64	  // --- Claim: standard reimbursement (no special clauses) ---
65	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (500 − 100 deductible)");
